import React, { useState, useEffect, useMemo } from 'react';
import Header from './components/Header';
import Flashcards from './components/Flashcards';
import Quiz from './components/Quiz';
import QuestionList from './components/QuestionList';
import { AppMode, Question } from './types';

// Modular Data Imports
import { questions as ch1 } from './hooks/data_ch1';
import { questions as ch3 } from './hooks/data_ch3';
import { questions as ch4 } from './hooks/data_ch4';
import { questions as ch6 } from './hooks/data_ch6';
import { questions as ch7 } from './hooks/data_ch7';
import { questions as ch8 } from './hooks/data_ch8';
import { questions as ch9 } from './hooks/data_ch9';
import { questions as ch10 } from './hooks/data_ch10';
import { questions as ch11 } from './hooks/data_ch11';

import { Trash2 } from 'lucide-react';

const App: React.FC = () => {
  const [currentMode, setCurrentMode] = useState<AppMode>(AppMode.FLASHCARDS);

  // PRIMARY DATA VAULT: Loads user modifications from local storage
  const [userVault, setUserVault] = useState<Question[]>(() => {
    try {
      const saved = localStorage.getItem('anatomy_ultimate_vault_v4');
      return saved ? JSON.parse(saved) : [];
    } catch (e) {
      console.error("Critical: Data Vault Access Denied", e);
      return [];
    }
  });

  // AUTO-PERSISTENCE: Every change to the vault is instantly locked into storage
  useEffect(() => {
    localStorage.setItem('anatomy_ultimate_vault_v4', JSON.stringify(userVault));
  }, [userVault]);

  // KNOWLEDGE BASE COMPILER: Merges system data with user data and removes duplicates
  const allQuestions = useMemo(() => {
    // 1. Gather all raw sources
    const systemSources = [
        ...ch1,
        ...ch3,
        ...ch4,
        ...ch6,
        ...ch7,
        ...ch8,
        ...ch9,
        ...ch10,
        ...ch11
    ];

    const combinedRaw = [...userVault, ...systemSources];

    // 2. Advanced De-duplication Logic
    // We use a Map where the key is a normalized version of the question text.
    // This removes duplicates that might have different IDs but same content.
    const uniqueMap = new Map<string, Question>();

    combinedRaw.forEach(q => {
        // Normalize: remove HTML tags, extra spaces, and lowercase
        const normalizedText = q.questionText.replace(/<[^>]*>/g, '').trim().toLowerCase();
        // Create a unique content signature
        const contentKey = `${normalizedText}|${q.category}`;

        if (uniqueMap.has(contentKey)) {
            const existing = uniqueMap.get(contentKey)!;

            // Conflict Resolution: Keep the "better" version
            // Priority 1: User Vault items (usually have custom IDs starting with 'global' or edited)
            if (userVault.some(uq => uq.id === q.id)) {
                uniqueMap.set(contentKey, q);
            }
            // Priority 2: Has Image vs No Image
            else if (!existing.questionImage && q.questionImage) {
                uniqueMap.set(contentKey, q);
            }
            // Priority 3: More Options defined
            else if ((existing.options?.length || 0) < (q.options?.length || 0)) {
                uniqueMap.set(contentKey, q);
            }
            // Otherwise keep existing (first come, first served)
        } else {
            uniqueMap.set(contentKey, q);
        }
    });

    // 3. Data Integrity & Option Validation Pass
    return Array.from(uniqueMap.values()).map(q => {
        // Ensure options array exists
        let cleanOptions = Array.isArray(q.options) ? [...q.options] : [];

        // Critical: Ensure the correct answer is present in options
        // We use loose comparison and trimming to catch slight variations
        const answerExists = cleanOptions.some(opt => 
            opt.trim().toLowerCase() === q.answerText.trim().toLowerCase()
        );

        if (!answerExists && q.answerText) {
            // Insert correct answer if missing
            if (cleanOptions.length >= 4) {
                cleanOptions.pop(); // Remove last distractor to make room
            }
            cleanOptions.push(q.answerText);
        }

        // Filter out empty options
        cleanOptions = cleanOptions.filter(opt => opt && opt.trim() !== '');

        return {
            ...q,
            options: cleanOptions
        };
    });
  }, [userVault]);

  const exportVault = () => {
    const dataStr = JSON.stringify(userVault, null, 2);
    const dataUri = 'data:application/json;charset=utf-8,' + encodeURIComponent(dataStr);
    const link = document.createElement('a');
    link.setAttribute('href', dataUri);
    link.setAttribute('download', `ANATOMY_MASTER_VAULT_${new Date().toISOString().split('T')[0]}.json`);
    link.click();
  };

  const importVault = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const imported = JSON.parse(e.target?.result as string) as Question[];
        if (Array.isArray(imported)) {
          setUserVault(prev => {
            const currentMap = new Map(prev.map(q => [q.id, q]));
            imported.forEach(q => currentMap.set(q.id, q));
            return Array.from(currentMap.values());
          });
          alert("Vault Re-Synchronized: Import Successful.");
        }
      } catch (err) {
        alert("Integrity Error: File format corrupted.");
      }
    };
    reader.readAsText(file);
  };

  const clearUserData = () => {
    if (confirm("WARNING: This will delete all your custom questions, progress, and saved edits from the Local Vault. Core system questions remain. Continue?")) {
      setUserVault([]);
      localStorage.removeItem('anatomy_ultimate_vault_v4');
      localStorage.removeItem('anatomy_quiz_session_v1');
      localStorage.removeItem('anatomy_quiz_mistakes_v1');
      window.location.reload();
    }
  };

  return (
    <div className="h-[100dvh] bg-slate-50 flex flex-col font-sans text-slate-900 selection:bg-blue-100 selection:text-blue-900 overflow-hidden">
      <Header currentMode={currentMode} onModeChange={setCurrentMode} />

      <main className="flex-1 relative overflow-hidden flex flex-col">
        {currentMode === AppMode.FLASHCARDS && (
          <div className="flex-1 h-full overflow-hidden py-4 md:py-6"><Flashcards data={allQuestions} /></div>
        )}
        {currentMode === AppMode.QUIZ && (
          <div className="flex-1 h-full overflow-hidden"><Quiz data={allQuestions} /></div>
        )}
        {currentMode === AppMode.LIST && (
          <div className="flex-1 h-full overflow-y-auto py-4 md:py-6">
            <QuestionList data={allQuestions} onExport={exportVault} onImport={importVault} />
            <div className="flex justify-center mt-12 mb-8">
               <button onClick={clearUserData} className="flex items-center gap-2 text-xs font-bold text-red-400 hover:text-red-600 uppercase tracking-widest transition-colors opacity-60 hover:opacity-100">
                 <Trash2 size={14} /> Factory Reset (Clear Local Vault)
               </button>
            </div>
          </div>
        )}
      </main>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import { Question, QuizQuestion } from '../types';
import Button from './Button';
import { 
  RotateCcw, 
  BrainCircuit, 
  Check, 
  X, 
  Clock, 
  Flag, 
  ChevronLeft, 
  ChevronRight, 
  LayoutGrid, 
  Image as ImageIcon, 
  Zap, 
  Hash, 
  Filter, 
  CheckCircle2,
  Lightbulb, 
  Shuffle,
  Maximize2,
  Play,
  Trophy,
  Target,
  Eye,
  List,
  BarChart3,
  AlertTriangle,
  Medal,
  Dna,
  Layers,
  RotateCw,
  ThumbsUp,
  ThumbsDown
} from 'lucide-react';

const SESSION_KEY = 'anatomy_quiz_session_v1';
const SETTINGS_KEY = 'anatomy_quiz_settings_v1';
const MISTAKES_KEY = 'anatomy_quiz_mistakes_v1';

const formatTime = (seconds: number) => {
  const mins = Math.floor(seconds / 60);
  const secs = seconds % 60;
  return `${mins}:${secs.toString().padStart(2, '0')}`;
};

interface QuizProps {
  data: Question[];
}

const Quiz: React.FC<QuizProps> = ({ data }) => {
  const [view, setView] = useState<'setup' | 'playing' | 'results' | 'review'>('setup');
  const [mode, setMode] = useState<'exam' | 'practice' | 'mistakes' | 'flashcard'>('exam');
  const [questions, setQuestions] = useState<QuizQuestion[]>([]);
  const [currentQIndex, setCurrentQIndex] = useState(0);
  const [timeLeft, setTimeLeft] = useState(0);
  const [zoomedImage, setZoomedImage] = useState<string | null>(null);
  const [isFlipped, setIsFlipped] = useState(false);

  // Settings
  const [questionCount, setQuestionCount] = useState(25);
  const [selectedGroups, setSelectedGroups] = useState<string[]>([]);
  const [showImagesOnly, setShowImagesOnly] = useState(false);
  const [isDropdownOpen, setIsDropdownOpen] = useState(false);
  const [showExplanations, setShowExplanations] = useState(true);
  const [shuffleQuestions, setShuffleQuestions] = useState(true);

  // Mobile Nav State
  const [isMobileNavOpen, setIsMobileNavOpen] = useState(false);

  // History
  const [mistakesHistory, setMistakesHistory] = useState<string[]>([]);
  const [imgError, setImgError] = useState(false);

  useEffect(() => {
    // Load settings
    const savedSettings = localStorage.getItem(SETTINGS_KEY);
    if (savedSettings) {
      try {
        const parsed = JSON.parse(savedSettings);
        if (parsed.customQuestionCount) setQuestionCount(parsed.customQuestionCount);
        if (parsed.showImagesOnly !== undefined) setShowImagesOnly(parsed.showImagesOnly);
        if (parsed.selectedGroups) setSelectedGroups(parsed.selectedGroups);
        if (parsed.mode && parsed.mode !== 'mistakes') setMode(parsed.mode);
        if (parsed.showExplanations !== undefined) setShowExplanations(parsed.showExplanations);
        if (parsed.shuffleQuestions !== undefined) setShuffleQuestions(parsed.shuffleQuestions);
      } catch (e) {
        console.error("Failed to load settings", e);
      }
    }

    // Load active session
    const savedSession = localStorage.getItem(SESSION_KEY);
    if (savedSession) {
      try {
        const parsed = JSON.parse(savedSession);
        if ((parsed.status === 'playing' || parsed.status === 'review') && parsed.questions && parsed.questions.length > 0) {
          setQuestions(parsed.questions);
          setCurrentQIndex(parsed.currentQIndex || 0);
          setTimeLeft(parsed.timeLeft || 0);
          setMode(parsed.mode || 'exam');
          setView(parsed.status);
        }
      } catch (e) {
        console.error("Failed to load session", e);
      }
    }

    // Load mistakes
    const savedMistakes = localStorage.getItem(MISTAKES_KEY);
    if (savedMistakes) {
      try {
        setMistakesHistory(JSON.parse(savedMistakes));
      } catch (e) {
        console.error("Failed to load mistakes", e);
      }
    }
  }, []);

  useEffect(() => {
    const settings = {
      customQuestionCount: questionCount,
      showImagesOnly,
      selectedGroups,
      mode: mode === 'mistakes' ? 'exam' : mode,
      showExplanations,
      shuffleQuestions
    };
    localStorage.setItem(SETTINGS_KEY, JSON.stringify(settings));
  }, [questionCount, showImagesOnly, selectedGroups, mode, showExplanations, shuffleQuestions]);

  useEffect(() => {
    if (view === 'playing' || view === 'review') {
      const session = {
        questions,
        currentQIndex,
        timeLeft,
        status: view,
        mode
      };
      localStorage.setItem(SESSION_KEY, JSON.stringify(session));
    } else {
      localStorage.removeItem(SESSION_KEY);
    }
  }, [questions, currentQIndex, timeLeft, view, mode]);

  useEffect(() => {
    if (view === 'results') {
      const newMistakes = new Set(mistakesHistory);
      questions.forEach(q => {
        if (q.userAnswer === q.correctOption) {
          newMistakes.delete(q.id);
        } else if (q.userAnswer === 'incorrect') {
          newMistakes.add(q.id);
        } else if (q.userAnswer && q.userAnswer !== q.correctOption) {
           newMistakes.add(q.id);
        }
      });
      const updatedMistakes = Array.from(newMistakes);
      localStorage.setItem(MISTAKES_KEY, JSON.stringify(updatedMistakes));
      setMistakesHistory(updatedMistakes);
    }
  }, [view]);

  useEffect(() => {
    setImgError(false);
    setIsFlipped(false);
  }, [currentQIndex]);

  const availableGroups = useMemo(() => {
    const groups = new Set<string>();
    data.forEach(q => { if (q.category) groups.add(q.category); });
    return Array.from(groups).sort();
  }, [data]);

  const maxPossibleQuestions = useMemo(() => {
    let count = 0;
    data.forEach(q => {
      if (showImagesOnly && (!q.questionImage || q.questionImage.trim() === '')) return;
      if (!q.answerText || q.answerText.trim() === '') return;
      const cat = q.category || 'General';
      if (selectedGroups.length > 0 && !selectedGroups.includes(cat)) return;
      count++;
    });
    return count;
  }, [data, selectedGroups, showImagesOnly]);

  useEffect(() => {
    if (questionCount > maxPossibleQuestions && maxPossibleQuestions > 0) {
      setQuestionCount(maxPossibleQuestions);
    }
    if (maxPossibleQuestions === 0) setQuestionCount(0);
    else if (questionCount === 0 && maxPossibleQuestions > 0) setQuestionCount(1);
  }, [maxPossibleQuestions, questionCount]);

  const toggleGroup = (group: string) => {
    setSelectedGroups(prev => 
      prev.includes(group) ? prev.filter(g => g !== group) : [...prev, group]
    );
  };

  const toggleAllGroups = () => {
    if (selectedGroups.length === availableGroups.length) {
      setSelectedGroups([]);
    } else {
      setSelectedGroups([...availableGroups]);
    }
  };

  const generateQuiz = (pool: Question[], count: number) => {
    let selectedQuestions = [...pool];

    // Deduplication check (just in case)
    const uniqueMap = new Map();
    selectedQuestions.forEach(q => uniqueMap.set(q.id, q));
    selectedQuestions = Array.from(uniqueMap.values());

    if (shuffleQuestions) {
        selectedQuestions.sort(() => Math.random() - 0.5);
    } else {
        selectedQuestions.sort((a, b) => a.id.localeCompare(b.id));
    }

    selectedQuestions = selectedQuestions.slice(0, count);

    return selectedQuestions.map(q => {
      const correct = q.answerText;
      let finalOptions: string[] = [];

      // Use existing options if they exist and are valid (contains correct answer)
      if (q.options && q.options.length >= 2) {
         // Create a clean set of options
         const uniqueOpts = Array.from(new Set(q.options.filter(o => o && o.trim() !== '')));

         // Ensure correct answer is present
         const hasCorrect = uniqueOpts.some(o => o.trim().toLowerCase() === correct.trim().toLowerCase());
         if (!hasCorrect) {
             uniqueOpts.push(correct);
         }

         finalOptions = uniqueOpts;

         // If we have way too many options, slice them, but keep the correct answer
         if (finalOptions.length > 5) {
             finalOptions = finalOptions.filter(o => o !== correct).slice(0, 3);
             finalOptions.push(correct);
         }
      } 

      // If we still have fewer than 4 options, generate distractors
      if (finalOptions.length < 4) {
        // Start with the correct answer if list is empty
        if (finalOptions.length === 0) finalOptions = [correct];

        // Find distractors from similar questions (same category)
        const isSingleWord = !correct.includes(' ');
        const categoryDistractors = Array.from(new Set(
          data
            .filter(i => {
                if (i.category !== q.category || i.answerText === correct || !i.answerText) return false;
                // Try to match answer style (single word vs sentence)
                if (isSingleWord && i.answerText.includes(' ')) return false;
                return true;
            })
            .map(i => i.answerText)
        )) as string[];

        const generalDistractors = Array.from(new Set(
          data
            .filter(i => i.category !== q.category && i.answerText !== correct && i.answerText)
            .map(i => i.answerText)
        )) as string[];

        // Fill needed slots
        const existingSet = new Set(finalOptions);
        let needed = 4 - finalOptions.length;

        // Try category specific first
        const validCatDistractors = categoryDistractors
          .filter(d => !existingSet.has(d))
          .sort(() => Math.random() - 0.5); // Shuffle candidates

        const takenCat = validCatDistractors.slice(0, needed);
        finalOptions = [...finalOptions, ...takenCat];

        // If still needed, try general
        needed = 4 - finalOptions.length;
        if (needed > 0) {
             const validGenDistractors = generalDistractors
              .filter(d => !existingSet.has(d))
              .sort(() => Math.random() - 0.5);
             const takenGen = validGenDistractors.slice(0, needed);
             finalOptions = [...finalOptions, ...takenGen];
        }
      }

      // Last resort fallback
      while (finalOptions.length < 4) {
        finalOptions.push(`Alternative Option ${finalOptions.length + 1}`);
      }

      // Final Shuffle of options
      finalOptions = finalOptions.sort(() => Math.random() - 0.5);

      return {
        id: q.id,
        data: q,
        options: finalOptions,
        correctOption: correct,
        userAnswer: null,
        isFlagged: false
      } as QuizQuestion;
    });
  };

  const startQuiz = () => {
    let pool = data.filter(q => q.answerText && q.answerText.trim() !== '');

    if (selectedGroups.length > 0) {
      pool = pool.filter(q => {
        const cat = q.category || 'General';
        return selectedGroups.includes(cat);
      });
    }

    if (showImagesOnly) {
      pool = pool.filter(q => q.questionImage && q.questionImage.trim() !== '');
    }

    if (pool.length === 0) {
      alert("No questions available matching your criteria.");
      return;
    }

    const count = Math.max(1, Math.min(questionCount, pool.length));
    const newQuestions = generateQuiz(pool, count);

    setQuestions(newQuestions);
    setCurrentQIndex(0);
    setTimeLeft(count * 60);
    setView('playing');
  };

  const startMistakesReview = () => {
    const pool = data.filter(q => mistakesHistory.includes(q.id));
    if (pool.length === 0) {
      alert("No mistakes found! Great job.");
      return;
    }

    setMode('mistakes');
    const newQuestions = generateQuiz(pool, pool.length);
    setQuestions(newQuestions);
    setCurrentQIndex(0);
    setTimeLeft(newQuestions.length * 60);
    setView('playing');
  };

  const clearMistakes = () => {
    if (confirm("Are you sure you want to clear your mistake history?")) {
      setMistakesHistory([]);
      localStorage.removeItem(MISTAKES_KEY);
    }
  };

  useEffect(() => {
    if ((view !== 'playing' && view !== 'review') || mode === 'practice' || mode === 'flashcard') return;

    const timer = setInterval(() => {
      setTimeLeft(prev => Math.max(0, prev - 1));
    }, 1000);

    return () => clearInterval(timer);
  }, [view, mode]);

  useEffect(() => {
    if (timeLeft === 0 && (view === 'playing' || view === 'review') && mode !== 'practice' && mode !== 'flashcard') {
      setView('results');
    }
  }, [timeLeft, view, mode]);

  const handleAnswer = (option: string) => {
    if (view === 'review') return;
    if ((mode === 'practice' || mode === 'flashcard') && questions[currentQIndex].userAnswer) return;

    setQuestions(prev => {
      const copy = [...prev];
      copy[currentQIndex].userAnswer = option;
      return copy;
    });

    if (mode === 'flashcard' && currentQIndex < questions.length - 1) {
        setTimeout(() => {
            setCurrentQIndex(prev => prev + 1);
        }, 300);
    }
  };

  const toggleFlag = (index: number = currentQIndex) => {
    setQuestions(prev => {
      const copy = [...prev];
      copy[index].isFlagged = !copy[index].isFlagged;
      return copy;
    });
  };

  const calculateScore = () => {
    const correct = questions.filter(q => q.userAnswer === q.correctOption || q.userAnswer === 'correct').length;
    return Math.round((correct / questions.length) * 100);
  };

  const handleFinishSession = () => {
    if (view === 'review') {
        if(confirm("Exit review mode and return to setup?")) {
            setView('setup');
            setIsMobileNavOpen(false);
        }
        return;
    }

    const unanswered = questions.filter(q => !q.userAnswer).length;
    const msg = unanswered > 0 
        ? `You have ${unanswered} unanswered questions. Submit exam now?` 
        : "Ready to submit your exam?";

    if (confirm(msg)) {
        setView('results');
        setIsMobileNavOpen(false);
    }
  };

  const ZoomModal = () => {
    if (!zoomedImage) return null;
    return (
      <div className="fixed inset-0 z-[100] bg-black/95 flex items-center justify-center p-2 md:p-4 animate-in fade-in duration-200" onClick={() => setZoomedImage(null)}>
        <button className="absolute top-4 right-4 text-white/70 hover:text-white p-2 transition-colors">
          <X size={28} />
        </button>
        <img 
          src={zoomedImage} 
          className="max-w-full max-h-full object-contain rounded-md shadow-2xl animate-in zoom-in-95 duration-300" 
          alt="Enlarged view" 
          onClick={(e) => e.stopPropagation()}
        />
      </div>
    );
  };

  if (view === 'setup') {
    return (
      <div className="flex flex-col h-full bg-slate-50 overflow-y-auto">
        <div className="flex-1 flex flex-col items-center justify-center p-3 md:p-8 min-h-min">
          <div className="w-full max-w-5xl bg-white rounded-3xl shadow-xl border border-slate-200 overflow-hidden my-auto animate-in fade-in slide-in-from-bottom-4 duration-500">

            <div className="bg-slate-900 p-5 md:p-8 flex items-center justify-between border-b border-slate-800">
              <div>
                <h1 className="text-xl md:text-3xl font-black text-white tracking-tight flex items-center gap-3">
                  <LayoutGrid className="text-blue-500 md:w-8 md:h-8" size={24} /> 
                  Assessment Setup
                </h1>
                <p className="text-slate-400 text-xs md:text-sm font-medium mt-1">Choose your testing environment.</p>
              </div>
              <div className="hidden sm:block text-right">
                 <div className="text-xl md:text-2xl font-black text-white">{maxPossibleQuestions}</div>
                 <div className="text-xs font-bold text-slate-500 uppercase tracking-widest">Questions</div>
              </div>
            </div>

            <div className="p-4 md:p-8 space-y-5 md:space-y-8">

              <div className="grid grid-cols-1 sm:grid-cols-3 gap-3 md:gap-4">
                <button 
                  onClick={() => setMode('exam')}
                  className={`relative overflow-hidden p-4 md:p-5 rounded-2xl border-2 transition-all flex flex-col items-center justify-center text-center gap-2 md:gap-3 group ${mode === 'exam' ? 'border-red-500 bg-red-50/50 shadow-lg shadow-red-100' : 'border-slate-200 hover:border-slate-300 hover:bg-slate-50'}`}
                >
                  <div className={`p-2.5 md:p-3 rounded-full ${mode === 'exam' ? 'bg-red-500 text-white' : 'bg-slate-100 text-slate-400 group-hover:bg-slate-200'}`}>
                    <Clock size={20} className="md:w-6 md:h-6" />
                  </div>
                  <div>
                    <div className={`font-black text-sm md:text-base ${mode === 'exam' ? 'text-red-700' : 'text-slate-600'}`}>Exam Mode</div>
                    <div className="text-[9px] md:text-[10px] font-bold opacity-60 uppercase tracking-wider">Timed • No Help</div>
                  </div>
                  {mode === 'exam' && <div className="absolute top-2 right-2 text-red-500"><CheckCircle2 size={16} /></div>}
                </button>

                <button 
                  onClick={() => setMode('practice')}
                  className={`relative overflow-hidden p-4 md:p-5 rounded-2xl border-2 transition-all flex flex-col items-center justify-center text-center gap-2 md:gap-3 group ${mode === 'practice' ? 'border-blue-500 bg-blue-50/50 shadow-lg shadow-blue-100' : 'border-slate-200 hover:border-slate-300 hover:bg-slate-50'}`}
                >
                  <div className={`p-2.5 md:p-3 rounded-full ${mode === 'practice' ? 'bg-blue-500 text-white' : 'bg-slate-100 text-slate-400 group-hover:bg-slate-200'}`}>
                    <Zap size={20} className="md:w-6 md:h-6" />
                  </div>
                  <div>
                    <div className={`font-black text-sm md:text-base ${mode === 'practice' ? 'text-blue-700' : 'text-slate-600'}`}>Practice Mode</div>
                    <div className="text-[9px] md:text-[10px] font-bold opacity-60 uppercase tracking-wider">Instant Answers</div>
                  </div>
                  {mode === 'practice' && <div className="absolute top-2 right-2 text-blue-500"><CheckCircle2 size={16} /></div>}
                </button>

                <button 
                  onClick={() => setMode('flashcard')}
                  className={`relative overflow-hidden p-4 md:p-5 rounded-2xl border-2 transition-all flex flex-col items-center justify-center text-center gap-2 md:gap-3 group ${mode === 'flashcard' ? 'border-amber-500 bg-amber-50/50 shadow-lg shadow-amber-100' : 'border-slate-200 hover:border-slate-300 hover:bg-slate-50'}`}
                >
                  <div className={`p-2.5 md:p-3 rounded-full ${mode === 'flashcard' ? 'bg-amber-500 text-white' : 'bg-slate-100 text-slate-400 group-hover:bg-slate-200'}`}>
                    <Layers size={20} className="md:w-6 md:h-6" />
                  </div>
                  <div>
                    <div className={`font-black text-sm md:text-base ${mode === 'flashcard' ? 'text-amber-700' : 'text-slate-600'}`}>Flashcard Quiz</div>
                    <div className="text-[9px] md:text-[10px] font-bold opacity-60 uppercase tracking-wider">Self-Assessed</div>
                  </div>
                  {mode === 'flashcard' && <div className="absolute top-2 right-2 text-amber-500"><CheckCircle2 size={16} /></div>}
                </button>
              </div>

              {mistakesHistory.length > 0 && (
                <div className="bg-amber-50 border-l-4 border-amber-400 rounded-r-xl p-4 flex flex-col sm:flex-row items-center justify-between shadow-sm gap-4">
                  <div className="flex items-center gap-4 w-full sm:w-auto">
                    <div className="bg-amber-100 p-2.5 rounded-full text-amber-600 shrink-0">
                      <BrainCircuit size={20} className="md:w-6 md:h-6" />
                    </div>
                    <div>
                      <h3 className="text-sm font-bold text-amber-900 uppercase tracking-wide">Review Needed</h3>
                      <p className="text-xs text-amber-700 font-medium">You have {mistakesHistory.length} questions queued for review.</p>
                    </div>
                  </div>
                  <div className="flex gap-2 w-full sm:w-auto">
                    <button onClick={startMistakesReview} className="flex-1 sm:flex-none flex items-center justify-center gap-2 px-5 py-2.5 bg-amber-500 hover:bg-amber-600 text-white text-xs font-bold uppercase rounded-lg shadow-md hover:shadow-lg transition-all active:scale-95">
                      <RotateCcw size={16} /> Review Now
                    </button>
                    <button onClick={clearMistakes} className="p-2.5 text-amber-600 hover:text-amber-800 hover:bg-amber-100 rounded-lg transition-colors" title="Clear history">
                      <X size={18} />
                    </button>
                  </div>
                </div>
              )}

              <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 md:gap-8">
                <div className="space-y-4 md:space-y-6">
                  <div className="flex justify-between items-center">
                    <label className="text-xs font-black text-slate-400 uppercase tracking-widest">Content Scope</label>
                    {selectedGroups.length > 0 && (
                      <button onClick={() => setSelectedGroups([])} className="text-[10px] font-bold text-red-500 hover:text-red-700 uppercase flex items-center gap-1 hover:bg-red-50 px-2 py-1 rounded transition-colors">
                        <X size={12} /> Clear
                      </button>
                    )}
                  </div>

                  <div className="relative">
                    <button 
                      onClick={() => setIsDropdownOpen(!isDropdownOpen)}
                      className={`w-full flex items-center justify-between p-3 md:p-4 rounded-xl border-2 transition-all shadow-sm ${isDropdownOpen ? 'border-blue-500 ring-4 ring-blue-50' : 'border-slate-200 bg-white hover:border-slate-300'}`}
                    >
                      <div className="flex items-center gap-3 text-slate-700 font-bold truncate">
                        <Filter size={18} className={selectedGroups.length > 0 ? "text-blue-500" : "text-slate-400"} />
                        <span className="truncate text-sm md:text-base">{selectedGroups.length === 0 ? 'All Topics Included' : `${selectedGroups.length} Topics Selected`}</span>
                      </div>
                      {isDropdownOpen ? <ChevronLeft className="rotate-90 text-blue-500 shrink-0" size={18} /> : <ChevronRight className="rotate-90 text-slate-400 shrink-0" size={18} />}
                    </button>

                    {isDropdownOpen && (
                      <>
                        <div className="fixed inset-0 z-10" onClick={() => setIsDropdownOpen(false)}></div>
                        <div 
                          className="absolute top-full left-0 w-full mt-3 bg-white border border-slate-200 rounded-2xl shadow-2xl z-20 overflow-hidden animate-in fade-in slide-in-from-top-2 duration-200"
                          onClick={(e) => e.stopPropagation()} 
                        >
                          <div className="p-3 bg-slate-50 border-b border-slate-100 flex justify-between items-center">
                            <span className="text-xs font-bold text-slate-500 uppercase tracking-wider pl-2">Available Modules</span>
                            <button onClick={toggleAllGroups} className="text-xs font-bold text-blue-600 hover:text-blue-700 hover:bg-blue-50 px-3 py-1.5 rounded-lg transition-colors">
                              {selectedGroups.length === availableGroups.length ? 'Deselect All' : 'Select All'}
                            </button>
                          </div>
                          <div className="max-h-64 overflow-y-auto p-2 custom-scrollbar">
                            {availableGroups.map(group => (
                              <label key={group} className="flex items-center gap-3 p-3 hover:bg-slate-50 rounded-xl cursor-pointer group transition-colors">
                                <div className="checkbox-wrapper relative w-5 h-5 shrink-0">
                                  <input 
                                    type="checkbox" 
                                    className="peer appearance-none w-full h-full border-2 border-slate-300 rounded bg-white checked:bg-blue-600 checked:border-blue-600 transition-all cursor-pointer"
                                    checked={selectedGroups.includes(group)}
                                    onChange={() => toggleGroup(group)}
                                  />
                                  <Check size={14} className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 text-white pointer-events-none hidden peer-checked:block" />
                                </div>
                                <span className={`text-sm font-bold transition-colors ${selectedGroups.includes(group) ? 'text-slate-900' : 'text-slate-500 group-hover:text-slate-700'}`}>{group}</span>
                              </label>
                            ))}
                          </div>
                        </div>
                      </>
                    )}
                  </div>

                  {selectedGroups.length > 0 && (
                    <div className="flex flex-wrap gap-2 p-4 bg-slate-50 border border-slate-200 rounded-2xl max-h-32 overflow-y-auto custom-scrollbar shadow-inner">
                      {selectedGroups.map(group => (
                        <span key={group} className="inline-flex items-center gap-1.5 px-2.5 py-1 bg-white text-slate-700 text-xs font-bold rounded-md border border-slate-200 shadow-sm animate-in zoom-in-50 duration-200">
                          {group}
                          <button onClick={() => toggleGroup(group)} className="text-slate-400 hover:text-red-500 hover:bg-red-50 rounded-full p-0.5 transition-colors">
                            <X size={12} />
                          </button>
                        </span>
                      ))}
                    </div>
                  )}
                </div>

                <div className="space-y-4 md:space-y-6">
                  <label className="text-xs font-black text-slate-400 uppercase tracking-widest">Configuration</label>

                  <div className="bg-slate-50 p-4 md:p-6 rounded-2xl border border-slate-200 space-y-5">
                    <div className="space-y-4">
                      <div className="flex justify-between items-center">
                        <div className="flex items-center gap-2 text-sm font-bold text-slate-700 uppercase tracking-wide">
                          <Hash size={16} className="text-blue-500" /> Quantity
                        </div>
                        <div className="flex items-center gap-2">
                           <input 
                              type="number" 
                              min="1" 
                              max={maxPossibleQuestions} 
                              value={questionCount}
                              onChange={(e) => {
                                const val = parseInt(e.target.value);
                                if (!isNaN(val)) {
                                  const safeVal = Math.min(Math.max(1, val), maxPossibleQuestions);
                                  setQuestionCount(safeVal);
                                }
                              }}
                              className="w-16 px-2 py-1 text-center font-black bg-white border border-slate-300 rounded-lg text-slate-800 outline-none focus:border-blue-500"
                            />
                            <span className="text-xs font-bold text-slate-400">/ {maxPossibleQuestions}</span>
                        </div>
                      </div>
                      <input 
                        type="range" 
                        min="1" 
                        max={maxPossibleQuestions} 
                        value={questionCount} 
                        onChange={(e) => setQuestionCount(parseInt(e.target.value))}
                        className="w-full accent-blue-600 h-2 bg-slate-200 rounded-lg appearance-none cursor-pointer"
                      />
                    </div>

                    <div className="h-px bg-slate-200"></div>

                    <div className="space-y-3">
                      <button 
                        onClick={() => setShuffleQuestions(!shuffleQuestions)}
                        className="w-full flex items-center justify-between group"
                      >
                        <span className="font-bold text-xs text-slate-600 flex items-center gap-2 group-hover:text-purple-600 transition-colors">
                          <Shuffle size={16} /> Randomize Order
                        </span>
                        <div className={`w-10 h-5 rounded-full relative transition-colors ${shuffleQuestions ? 'bg-purple-600' : 'bg-slate-300'}`}>
                          <div className={`absolute top-1 w-3 h-3 rounded-full bg-white transition-all shadow-sm ${shuffleQuestions ? 'left-6' : 'left-1'}`}></div>
                        </div>
                      </button>

                      <button 
                        onClick={() => setShowImagesOnly(!showImagesOnly)}
                        className="w-full flex items-center justify-between group"
                      >
                        <span className="font-bold text-xs text-slate-600 flex items-center gap-2 group-hover:text-blue-600 transition-colors">
                          <ImageIcon size={16} /> Diagrams Only
                        </span>
                        <div className={`w-10 h-5 rounded-full relative transition-colors ${showImagesOnly ? 'bg-blue-600' : 'bg-slate-300'}`}>
                          <div className={`absolute top-1 w-3 h-3 rounded-full bg-white transition-all shadow-sm ${showImagesOnly ? 'left-6' : 'left-1'}`}></div>
                        </div>
                      </button>

                      <button 
                        onClick={() => setShowExplanations(!showExplanations)}
                        className="w-full flex items-center justify-between group"
                      >
                        <span className="font-bold text-xs text-slate-600 flex items-center gap-2 group-hover:text-amber-600 transition-colors">
                          <Lightbulb size={16} /> Enable Explanations
                        </span>
                        <div className={`w-10 h-5 rounded-full relative transition-colors ${showExplanations ? 'bg-amber-500' : 'bg-slate-300'}`}>
                          <div className={`absolute top-1 w-3 h-3 rounded-full bg-white transition-all shadow-sm ${showExplanations ? 'left-6' : 'left-1'}`}></div>
                        </div>
                      </button>
                    </div>
                  </div>
                </div>
              </div>

              <div className="pt-2">
                <Button 
                  variant="primary" 
                  onClick={startQuiz} 
                  fullWidth 
                  className="py-4 md:py-5 text-base md:text-xl rounded-2xl shadow-xl shadow-blue-500/20 hover:shadow-blue-500/30 hover:-translate-y-1 active:translate-y-0 transition-all bg-gradient-to-r from-blue-600 to-indigo-700 border-none relative overflow-hidden group"
                  disabled={maxPossibleQuestions === 0}
                >
                  <div className="absolute inset-0 bg-white/20 translate-y-full group-hover:translate-y-0 transition-transform duration-300"></div>
                  <div className="relative flex items-center gap-3">
                    {maxPossibleQuestions === 0 ? (
                      'No Questions Match Filter'
                    ) : (
                      <>
                        <Play className="fill-current" size={20} />
                        Start Session ({mode === 'flashcard' ? 'Flashcards' : mode === 'exam' ? 'Exam' : 'Practice'})
                      </>
                    )}
                  </div>
                </Button>
                <p className="text-center text-xs font-bold text-slate-400 mt-4 uppercase tracking-widest">
                  {maxPossibleQuestions > 0 ? `Ready to launch with ${questionCount} questions` : 'Adjust filters to continue'}
                </p>
              </div>
            </div>
          </div>
        </div>
      </div>
    );
  }

  const currentQ = questions[currentQIndex];

  const QuestionNavigator = () => {
    const answeredCount = questions.filter(q => q.userAnswer).length;

    return (
      <div className="bg-white rounded-2xl lg:rounded-3xl border border-slate-200 shadow-sm overflow-hidden flex flex-col h-full lg:max-h-[calc(100vh-8rem)]">
        <div className="flex-none p-4 border-b border-slate-100 bg-slate-50/50">
          <div className="flex items-center justify-between mb-4">
             <span className="text-xs font-black text-slate-400 uppercase tracking-widest">Session Status</span>
             <div className={`px-2.5 py-1 rounded-lg text-[10px] font-bold uppercase tracking-wide ${mode === 'exam' ? 'bg-red-50 text-red-600 border border-red-100' : mode === 'flashcard' ? 'bg-amber-50 text-amber-600 border border-amber-100' : 'bg-blue-50 text-blue-600 border border-blue-100'}`}>
                {mode}
             </div>
          </div>

          <div className="flex items-center gap-2 mb-2">
             <div className="flex-1 bg-white border border-slate-200 rounded-xl p-2 text-center shadow-sm">
                <span className="block text-[10px] font-bold text-slate-400 uppercase">Time</span>
                <span className={`block font-mono font-black text-base ${timeLeft < 60 ? 'text-red-500 animate-pulse' : 'text-slate-800'}`}>
                   {(mode === 'practice' || mode === 'flashcard') ? '--:--' : formatTime(timeLeft)}
                </span>
             </div>
             <div className="flex-1 bg-white border border-slate-200 rounded-xl p-2 text-center shadow-sm">
                <span className="block text-[10px] font-bold text-slate-400 uppercase">Solved</span>
                <span className="block font-mono font-black text-base text-slate-800">
                   {answeredCount}<span className="text-slate-300 font-medium">/{questions.length}</span>
                </span>
             </div>
          </div>
        </div>

        <div className="flex-1 overflow-y-auto min-h-0 custom-scrollbar p-3">
           <div className="grid grid-cols-5 gap-1.5">
              {questions.map((q, idx) => {
                 let statusClass = "bg-white border-slate-100 text-slate-400 hover:border-blue-200 hover:text-blue-500";
                 if (idx === currentQIndex) {
                    statusClass = "ring-2 ring-blue-500 border-blue-500 bg-blue-50 text-blue-700 z-10 shadow-md";
                 } else if (q.isFlagged) {
                    statusClass = "bg-amber-100 border-amber-300 text-amber-700";
                 } else if (q.userAnswer === 'correct') {
                    statusClass = "bg-emerald-600 border-emerald-600 text-white shadow-sm";
                 } else if (q.userAnswer === 'incorrect') {
                    statusClass = "bg-rose-600 border-rose-600 text-white shadow-sm";
                 } else if (q.userAnswer) {
                    statusClass = "bg-blue-600 border-blue-600 text-white shadow-sm";
                 }

                 return (
                    <button
                      key={q.id}
                      onClick={() => {
                        setCurrentQIndex(idx);
                        setIsMobileNavOpen(false);
                      }}
                      className={`aspect-square rounded-lg border flex items-center justify-center text-xs font-black transition-all relative ${statusClass}`}
                    >
                       {idx + 1}
                       {q.isFlagged && <div className="absolute top-0.5 right-0.5 w-1.5 h-1.5 bg-amber-500 rounded-full"></div>}
                    </button>
                 )
              })}
           </div>
        </div>

        <div className="flex-none p-3 border-t border-slate-100 bg-white space-y-2 shadow-[0_-10px_20px_rgba(0,0,0,0.02)]">
             <button 
                onClick={handleFinishSession}
                className={`w-full py-3 md:py-4 rounded-xl font-black uppercase tracking-widest transition-all flex items-center justify-center gap-2 shadow-lg text-xs transform active:scale-95 ${
                    view === 'review' 
                    ? 'bg-slate-100 text-slate-600 hover:bg-slate-200 border border-slate-200' 
                    : 'bg-slate-900 text-white hover:bg-slate-800 shadow-slate-900/20'
                }`}
            >
                {view === 'review' ? <LayoutGrid size={16} /> : <CheckCircle2 size={16} />}
                {view === 'review' ? 'End Review' : 'Submit Session'}
            </button>
            <div className="text-[9px] font-black text-slate-400 flex justify-between gap-1 uppercase tracking-tighter pt-1 px-1">
               <div className="flex items-center gap-1"><div className="w-1.5 h-1.5 rounded-full bg-blue-600"></div>Done</div>
               <div className="flex items-center gap-1"><div className="w-1.5 h-1.5 rounded-full bg-amber-400"></div>Flag</div>
               <div className="flex items-center gap-1"><div className="w-1.5 h-1.5 rounded-full border border-slate-200"></div>Open</div>
            </div>
        </div>
      </div>
    )
  }

  if (view === 'playing' || view === 'review') {
    return (
      <div className="h-full flex flex-col w-full bg-slate-50 relative overflow-hidden">
        <ZoomModal />

        {isMobileNavOpen && (
          <div className="fixed inset-0 z-50 bg-slate-900/40 backdrop-blur-sm lg:hidden" onClick={() => setIsMobileNavOpen(false)}>
             <div className="absolute right-0 top-0 bottom-0 w-full max-w-[280px] bg-white shadow-2xl animate-in slide-in-from-right duration-300 h-full" onClick={e => e.stopPropagation()}>
                <QuestionNavigator />
             </div>
          </div>
        )}

        <div className="max-w-[1400px] mx-auto w-full h-full p-2 md:p-4 flex gap-4 overflow-hidden">
           <div className="flex-1 flex flex-col h-full gap-2 md:gap-4 min-w-0">
              <div className="flex justify-between items-center bg-white p-2 md:p-3 rounded-2xl border border-slate-200 shadow-sm shrink-0">
                 <div className="flex items-center gap-3">
                    <span className="px-2.5 py-1 bg-slate-900 text-white rounded-lg text-[10px] font-black uppercase tracking-wider">
                       Q {currentQIndex + 1}
                    </span>
                    <span className="text-[10px] font-bold text-slate-500 truncate hidden sm:block max-w-xs uppercase tracking-wide">
                       {currentQ.data.category}
                    </span>
                 </div>

                 <div className="flex items-center gap-2">
                    <button 
                      onClick={() => setIsMobileNavOpen(true)}
                      className="lg:hidden p-2 rounded-lg bg-slate-50 border border-slate-200 text-slate-600 hover:bg-white transition-colors"
                    >
                       <List size={18} />
                    </button>
                    <button 
                      onClick={() => toggleFlag()}
                      className={`p-2 rounded-lg border transition-all flex items-center gap-2 text-[10px] font-bold uppercase tracking-wide ${currentQ.isFlagged ? 'bg-amber-100 border-amber-200 text-amber-700' : 'bg-white border-slate-200 text-slate-400 hover:text-amber-500'}`}
                    >
                      <Flag size={14} className={currentQ.isFlagged ? "fill-current" : ""} />
                      <span className="hidden sm:inline">Flag</span>
                    </button>
                    <button 
                      onClick={() => {
                        if (confirm('End session and return to setup? Progress will be lost.')) {
                          setView('setup');
                          localStorage.removeItem(SESSION_KEY);
                        }
                      }}
                      className="p-2 rounded-lg bg-white border border-slate-200 text-slate-400 hover:text-red-500 hover:bg-red-50 transition-colors"
                    >
                      <X size={18} />
                    </button>
                 </div>
              </div>

              <div className="flex-1 bg-white rounded-2xl md:rounded-3xl border border-slate-200 shadow-sm overflow-hidden flex flex-col relative">
                 <div className="flex-1 overflow-y-auto custom-scrollbar p-3 md:p-10">
                    <div className="max-w-3xl mx-auto space-y-4 md:space-y-8">

                       {mode === 'flashcard' && view === 'playing' ? (
                         <div className="h-full min-h-[40vh] flex flex-col">
                            <div 
                                onClick={() => setIsFlipped(!isFlipped)}
                                className={`flex-1 relative cursor-pointer perspective-1000 group transition-all duration-500 ${isFlipped ? '[transform:rotateY(180deg)]' : ''}`}
                                style={{ transformStyle: 'preserve-3d' }}
                            >
                                {/* FRONT */}
                                <div className="absolute inset-0 bg-white border-2 border-slate-100 rounded-[2rem] flex flex-col items-center justify-center p-4 md:p-8 backface-hidden shadow-sm group-hover:border-blue-200 transition-colors">
                                    <span className="text-[9px] md:text-[10px] font-black text-slate-300 uppercase tracking-widest mb-4 md:mb-6">Question Matrix</span>
                                    {currentQ.data.questionImage && !imgError && (
                                        <div className="mb-4 md:mb-6 max-h-[25vh] md:max-h-[30vh] overflow-hidden">
                                            <img src={currentQ.data.questionImage} className="max-h-full object-contain mix-blend-multiply" alt="Diagram" onError={() => setImgError(true)} />
                                        </div>
                                    )}
                                    <div className="text-lg md:text-3xl font-black text-center text-slate-900 leading-tight" dangerouslySetInnerHTML={{ __html: currentQ.data.questionText }} />
                                    <div className="mt-6 md:mt-10 flex items-center gap-2 text-slate-400 font-bold text-xs uppercase tracking-widest">
                                        <RotateCw size={14} /> Tap to reveal answer
                                    </div>
                                </div>
                                {/* BACK */}
                                <div className="absolute inset-0 bg-slate-900 border-2 border-slate-800 rounded-[2rem] flex flex-col items-center justify-center p-4 md:p-8 backface-hidden shadow-2xl [transform:rotateY(180deg)] overflow-hidden">
                                    <div className="absolute inset-0 bg-gradient-to-br from-blue-600/5 to-transparent"></div>
                                    <span className="text-[9px] md:text-[10px] font-black text-blue-400 uppercase tracking-widest mb-4 md:mb-6 relative z-10">Scientific Response</span>
                                    <div className="text-xl md:text-4xl font-black text-center text-white leading-tight relative z-10" dangerouslySetInnerHTML={{ __html: currentQ.data.answerText }} />
                                    {currentQ.data.explanation && (
                                        <div className="mt-4 md:mt-8 bg-white/5 border border-white/10 p-3 md:p-5 rounded-2xl text-slate-400 text-xs md:text-sm max-w-md text-center leading-relaxed relative z-10">
                                            <span dangerouslySetInnerHTML={{ __html: currentQ.data.explanation }} />
                                        </div>
                                    )}
                                </div>
                            </div>

                            {isFlipped && !currentQ.userAnswer && (
                                <div className="flex gap-3 md:gap-4 mt-4 md:mt-8 animate-in slide-in-from-bottom-4 duration-300">
                                    <button 
                                        onClick={() => handleAnswer('incorrect')}
                                        className="flex-1 py-3 md:py-6 bg-white border-2 border-rose-100 text-rose-500 rounded-2xl font-black uppercase tracking-widest flex items-center justify-center gap-2 md:gap-3 hover:bg-rose-50 transition-all shadow-md active:scale-95 text-xs md:text-base"
                                    >
                                        <ThumbsDown size={18} className="md:w-6 md:h-6" /> Incorrect
                                    </button>
                                    <button 
                                        onClick={() => handleAnswer('correct')}
                                        className="flex-1 py-3 md:py-6 bg-emerald-600 text-white rounded-2xl font-black uppercase tracking-widest flex items-center justify-center gap-2 md:gap-3 hover:bg-emerald-500 transition-all shadow-xl shadow-emerald-500/20 active:scale-95 text-xs md:text-base"
                                    >
                                        <ThumbsUp size={18} className="md:w-6 md:h-6" /> I Knew It
                                    </button>
                                </div>
                            )}

                            {currentQ.userAnswer && (
                                <div className={`mt-4 md:mt-8 p-4 md:p-6 rounded-2xl flex items-center justify-center gap-3 md:gap-4 animate-in zoom-in-95 duration-300 ${currentQ.userAnswer === 'correct' ? 'bg-emerald-50 text-emerald-700' : 'bg-rose-50 text-rose-700'}`}>
                                    {currentQ.userAnswer === 'correct' ? <CheckCircle2 size={20} className="md:w-6 md:h-6" /> : <AlertTriangle size={20} className="md:w-6 md:h-6" />}
                                    <span className="font-black uppercase tracking-widest text-xs md:text-base">Logged as {currentQ.userAnswer}</span>
                                </div>
                            )}
                         </div>
                       ) : (
                         <>
                            <div className="flex items-start justify-between gap-4">
                                <div className="text-base md:text-xl font-bold text-slate-900 leading-relaxed tracking-tight">
                                    <span dangerouslySetInnerHTML={{ __html: currentQ.data.questionText }} />
                                </div>
                            </div>

                            {currentQ.data.questionImage && !imgError && (
                                <div 
                                    className="w-full bg-slate-50 rounded-2xl border border-slate-100 p-2 md:p-4 flex justify-center cursor-zoom-in hover:border-blue-200 transition-colors group relative"
                                    onClick={() => setZoomedImage(currentQ.data.questionImage!)}
                                >
                                    <img 
                                    src={currentQ.data.questionImage} 
                                    className="max-h-[25vh] md:max-h-[35vh] object-contain mix-blend-multiply"
                                    onError={() => setImgError(true)}
                                    alt="Question Diagram"
                                    />
                                    <div className="absolute top-4 right-4 bg-white/80 backdrop-blur-sm shadow-sm p-1.5 rounded-lg opacity-0 group-hover:opacity-100 transition-opacity pointer-events-none">
                                        <Maximize2 size={14} className="text-slate-500" />
